PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE usuarios (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    nombre_completo TEXT NOT NULL,
    ci TEXT NOT NULL UNIQUE, -- Cédula de Identidad
    cargo TEXT,
    unidad TEXT,
    oficina TEXT,
    piso TEXT,
    fecha_registro DATETIME DEFAULT CURRENT_TIMESTAMP
, registrado_por TEXT);
CREATE TABLE activos (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    codigo_activo TEXT NOT NULL UNIQUE,
    descripcion TEXT NOT NULL,
    serie TEXT,
    estado_actual TEXT CHECK(estado_actual IN ('Disponible', 'Asignado', 'Mantenimiento')) DEFAULT 'Disponible',
    usuario_actual_id INTEGER, -- ID del usuario que tiene el activo actualmente
    unidad TEXT,               -- Ubicación actual del activo (Unidad)
    oficina TEXT,              -- Ubicación actual del activo (Oficina)
    piso TEXT, registrado_por TEXT,                 -- Ubicación actual del activo (Piso)
    FOREIGN KEY (usuario_actual_id) REFERENCES usuarios(id)
);
CREATE TABLE actas (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    tipo_acta TEXT CHECK(tipo_acta IN ('Asignación', 'Devolución')) NOT NULL,
    usuario_id INTEGER NOT NULL,
    fecha_emision DATETIME DEFAULT CURRENT_TIMESTAMP,
    observaciones TEXT,
    archivo_pdf_url TEXT, unidad TEXT, oficina TEXT, piso TEXT, realizado_por TEXT,
    FOREIGN KEY (usuario_id) REFERENCES usuarios(id)
);
CREATE TABLE detalles_acta (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    acta_id INTEGER NOT NULL,
    activo_id INTEGER NOT NULL,
    estado_fisico TEXT CHECK(estado_fisico IN ('Bueno', 'Regular', 'Malo')) DEFAULT 'Bueno',
    FOREIGN KEY (acta_id) REFERENCES actas(id),
    FOREIGN KEY (activo_id) REFERENCES activos(id)
);
CREATE TABLE auditorias_fisicas (id INTEGER PRIMARY KEY AUTOINCREMENT, usuario_auditado_id INTEGER NOT NULL, activo_id INTEGER NOT NULL, hallazgo TEXT CHECK(hallazgo IN ('Correcto', 'Sobrante', 'Ajeno')) NOT NULL, fecha_auditoria DATETIME DEFAULT CURRENT_TIMESTAMP, realizado_por TEXT, observacion TEXT, FOREIGN KEY (usuario_auditado_id) REFERENCES usuarios(id), FOREIGN KEY (activo_id) REFERENCES activos(id));
CREATE TABLE system_users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT UNIQUE NOT NULL,
    nombre TEXT NOT NULL,
    password_hash TEXT NOT NULL,  -- SHA-256 hex
    rol TEXT CHECK(rol IN ('admin', 'tecnico')) DEFAULT 'tecnico',
    activo INTEGER DEFAULT 1,
    created_at TEXT DEFAULT (datetime('now'))
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_usuarios_ci ON usuarios(ci);
CREATE INDEX idx_activos_codigo ON activos(codigo_activo);
